// Analytics is never on the critical path.
// A fallback segment is always better than a blocked flow.
// Record the degradation level so downstream nodes can adapt.

try {
  const segmentResult = await this.db.searchDocuments(ANALYTICS_SEGMENTS_INDEX, { user_id });
  if (segmentResult.isSuccess && segmentResult.data?.length > 0) {
    segment = segmentResult.data[0].segment;  // 'TECH_STARTUP', 'SMB', etc.
    signalsUsed++;
  } else {
    // A2 degraded — use GENERAL fallback
    segment = 'GENERAL';
    confidence = 0.0;
    degradationLevel += 1;  // ← recorded, not silenced
  }
} catch {
  // A2 exception — same GENERAL fallback, same degradation record
  segment = 'GENERAL'; confidence = 0.0; degradationLevel += 1;
}

// Four independent fallbacks — A1/A2/A3/B1 each degrade independently
// degradationLevel: 0=full, 1-3=partial, 4=all-absent (trending content used)
// FLOW-04 reads degradationLevel to adapt the UI (show 'improving your feed' banner)
